mapper.select:
SELECT b.BATTLE_ID, b.COURSE_ID, b.USER_ID, b.WORKRECORD_ID, b.BATTLE_NAME, b.MODE, b.STATUS, b.START_DATETIME, b.END_DATETIME, b.TEAM_SIZE, b.GENDER_TYPE, c.COURSE_NAME AS COURSE_NAME, u.NICKNAME AS OWNER_NICKNAME FROM BATTLE b JOIN JOIN_BATTLE jb ON jb.BATTLE_ID = b.BATTLE_ID JOIN COURSE c ON b.COURSE_ID = c.COURSE_ID JOIN USERS u ON b.USER_ID = u.USER_ID WHERE jb.USER_ID = #{userId}
AND b.STATUS = #{status}
ORDER BY b.START_DATETIME DESC LIMIT #{limit} OFFSET #{offset}

SELECT U.USER_ID AS USER_ID, U.NICKNAME AS NICKNAME, COUNT(*) AS WIN_COUNT, U.LEVEL_ID AS LEVEL, A.AVATAR_IMG AS AVATAR_URL FROM JOIN_BATTLE JB JOIN BATTLE B ON JB.BATTLE_ID = B.BATTLE_ID JOIN USERS U ON JB.USER_ID = U.USER_ID LEFT JOIN AVATAR A ON U.AVATAR_ID = A.AVATAR_ID WHERE JB.WIN_STATUS = 0 AND B.STATUS = 2
AND B.MODE = #{mode}
AND U.GENDER = #{genderType}
GROUP BY U.USER_ID, U.NICKNAME, U.LEVEL_ID, A.AVATAR_IMG ORDER BY WIN_COUNT DESC, U.USER_ID LIMIT 10

SELECT B.BATTLE_ID, B.COURSE_ID, B.USER_ID, B.WORKRECORD_ID, B.BATTLE_NAME, B.MODE, B.STATUS, B.START_DATETIME, B.END_DATETIME, B.TEAM_SIZE, B.GENDER_TYPE, C.COURSE_NAME AS COURSE_NAME, U.NICKNAME AS OWNER_NICKNAME FROM BATTLE B JOIN COURSE C ON B.COURSE_ID = C.COURSE_ID JOIN USERS U ON B.USER_ID = U.USER_ID WHERE 1 = 1
AND B.BATTLE_NAME LIKE CONCAT('%', #{searchKeyword}, '%')
AND B.MODE = #{mode}
AND B.STATUS = #{status}
AND B.GENDER_TYPE = #{genderType}
AND DATE_FORMAT(B.START_DATETIME, '%Y-%m-%d') LIKE CONCAT(#{searchStartDate}, '%')
ORDER BY B.STATUS ASC, B.START_DATETIME DESC
ORDER BY ( 6371000 * 2 * ASIN( SQRT( POW(SIN((RADIANS(ST_X(C.START_POINT)) - RADIANS(#{userLat})) / 2), 2) + COS(RADIANS(#{userLat})) * COS(RADIANS(ST_X(C.START_POINT))) * POW(SIN((RADIANS(ST_Y(C.START_POINT)) - RADIANS(#{userLng})) / 2), 2) ) ) ) ASC, B.START_DATETIME DESC
ORDER BY B.START_DATETIME DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE BATTLE
SET STATUS = #{status}
WHERE BATTLE_ID = #{battleId}

mapper.select:
SELECT COUNT(*)
FROM JOIN_BATTLE
WHERE BATTLE_ID = #{battleId}
